import React, { useState } from 'react';

function ProductCard({ product }) {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);

  return (
    <div className="product-card">
      <div className="product-image">
        {!imageError ? (
          <>
            {!imageLoaded && (
              <div className="image-skeleton">
                <span className="flower-emoji">🌸</span>
              </div>
            )}
            <img
              src={product.image}
              alt={product.name}
              className={`product-img ${imageLoaded ? 'loaded' : ''}`}
              onLoad={() => setImageLoaded(true)}
              onError={() => setImageError(true)}
              loading="lazy"
            />
          </>
        ) : (
          <div className="fallback-emoji">
            <span className="flower-emoji">🌸</span>
          </div>
        )}
        {product.featured && (
          <span className="featured-badge">✨ Fresh Today</span>
        )}
      </div>
      <div className="product-info">
        <h3 className="product-name">{product.name}</h3>
        <span className="product-category">{product.category}</span>
        <p className="product-description">{product.description}</p>
        <div className="product-footer">
          <span className="product-price">${product.price}</span>
          <button className="add-to-cart-btn" aria-label={`Add ${product.name} to cart`}>
            🛒 Add
          </button>
        </div>
      </div>
    </div>
  );
}

export default React.memo(ProductCard);
